function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right and down
    const dirs = [[0, 1], [1, 0]];

    // Initialize a 2D array to store the minimum cost to reach each cell
    // We use a 2D array of size (m x n) to store the minimum cost
    const dp: number[][] = Array(m).fill(null).map(() => Array(n).fill(Infinity));

    // Starting point: (0, 0)
    dp[0][0] = 1; // Entry cost of (0, 0)

    // Use a priority queue to perform Dijkstra's algorithm
    // Each element in the queue is [cost, row, col, time]
    const pq: [number, number, number, number][] = [[1, 0, 0, 1]]; // time starts at 1

    while (pq.length > 0) {
        // Extract the element with the minimum cost
        const [cost, row, col, time] = pq.shift() as [number, number, number, number];

        // If we have reached the destination, return the cost
        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        // If the current cost is higher than the recorded minimum cost, skip
        if (cost > dp[row][col]) {
            continue;
        }

        // Determine if it's an odd or even time step
        const isOddTime = time % 2 === 1;

        if (isOddTime) {
            // Move to adjacent cell (right or down)
            for (const [dr, dc] of dirs) {
                const newRow = row + dr;
                const newCol = col + dc;

                // Check if the new cell is within bounds
                if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                    // Calculate the entry cost of the new cell
                    const entryCost = (newRow + 1) * (newCol + 1);
                    const newCost = cost + entryCost;

                    // Update the DP table if this is a better path
                    if (newCost < dp[newRow][newCol]) {
                        dp[newRow][newCol] = newCost;
                        pq.push([newCost, newRow, newCol, time + 1]);
                    }
                }
            }
        } else {
            // Wait in the current cell
            const waitCostValue = waitCost[row][col];
            const newCost = cost + waitCostValue;

            // Update the DP table if this is a better path
            if (newCost < dp[row][col]) {
                dp[row][col] = newCost;
                pq.push([newCost, row, col, time + 1]);
            }
        }
    }

    // If we reach here, it means there is no path (should not happen for valid inputs)
    return -1;
}

